understanding_checks.code:
def make_bold(func):
    def wrapper():
        return f"<b>{func()}</b>"
    return wrapper

@make_bold
def get_text():
    return "Hello"

print(get_text())

def log_execution(func):
    def wrapper(*args, **kwargs):
        print("Executing function...")
        func(*args, **kwargs)
    return wrapper

@log_execution
def add(a, b):
    return a + b

result = add(2, 3)

