practice_tasks.solution_code:
def log_call(func):
    def wrapper():
        print('Calling function')
        func()
        print('Function finished')
    return wrapper

@log_call
def say_hello():
    print('Hello!')

say_hello()

code_walkthrough.code:
def uppercase(func):
  def wrapper():
    original_result = func()
    return original_result.upper()
  return wrapper

@uppercase
def greet():
  return 'hello'

print(greet())

